import React from 'react';

const About = () => {
    return (
        <section>
            <h2 style={{ textAlign: 'center', color: 'var(--accent-color)' }}>About Me</h2>
            <div className="glass-card">
                <p>I'm a passionate Web Developer and Technical Support Specialist with over 3 years of experience. I specialize in front-end development using HTML, CSS, JavaScript, Vue, and Bootstrap. I value clean code, responsive design, and beautiful UI.</p>
            </div>
        </section>
    );
};

export default About;
